import { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { getSettings, saveSettings, getAllCustomExercises } from '../db';

const AppContext = createContext(null);

const DEFAULTS = { key: 'main', units: 'kg', defaultRest: 90, keepAwake: true, rpeEnabled: false };

export function AppProvider({ children }) {
  const [settings, setSettings] = useState(DEFAULTS);
  const [customExercises, setCustomExercises] = useState([]);

  useEffect(() => {
    getSettings().then(s => setSettings({ ...DEFAULTS, ...s }));
    getAllCustomExercises().then(setCustomExercises);
  }, []);

  const updateSetting = async (key, value) => {
    const next = { ...settings, [key]: value };
    setSettings(next);
    await saveSettings(next);
  };

  const refreshExercises = useCallback(() => {
    getAllCustomExercises().then(setCustomExercises);
  }, []);

  return (
    <AppContext.Provider value={{ settings, updateSetting, customExercises, refreshExercises }}>
      {children}
    </AppContext.Provider>
  );
}

export function useApp() {
  return useContext(AppContext);
}
